 69→    );
 70→  }
 71→
 72→  if (!storyQuery.data) {
 73→    return (
 74→      <Screen>
 75→        <Text style={styles.error}>Story not found.</Text>
 76→      </Screen>
 77→    );
 78→  }
 79→
 80→  const story = storyQuery.data;
 81→  const chapters = story.chapters ?? [];
